    emptyOutDir: true,
  },
  server: {
    fs: {
      strict: true,
      deny: ["**/.*"],
    },
  },
});

server/index.ts.content:
import express, { type Request, Response, NextFunction } from "express";
import { registerRoutes } from "./routes";
import { setupVite, serveStatic, log } from "./vite";

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: false }));

app.use((req, res, next) => {
  const start = Date.now();
  const path = req.path;
  let capturedJsonResponse: Record<string, any> | undefined = undefined;

  const originalResJson = res.json;
  res.json = function (bodyJson, ...args) {
    capturedJsonResponse = bodyJson;
    return originalResJson.apply(res, [bodyJson, ...args]);
  };

  res.on("finish", () => {
    const duration = Date.now() - start;
    if (path.startsWith("/api")) {
      let logLine = `${req.method} ${path} ${res.statusCode} in ${duration}ms`;
      if (capturedJsonResponse) {
        logLine += ` :: ${JSON.stringify(capturedJsonResponse)}`;
      }

      if (logLine.length > 80) {
        logLine = logLine.slice(0, 79) + "…";
      }

      log(logLine);
    }
  });

  next();
});

(async () => {
  const server = await registerRoutes(app);

  app.use((err: any, _req: Request, res: Response, _next: NextFunction) => {
    const status = err.status || err.statusCode || 500;
    const message = err.message || "Internal Server Error";

    res.status(status).json({ message });
    throw err;
  });

  // importantly only setup vite in development and after
  // setting up all the other routes so the catch-all route
  // doesn't interfere with the other routes
  if (app.get("env") === "development") {
    await setupVite(app, server);
  } else {
    serveStatic(app);
  }

  // ALWAYS serve the app on the port specified in the environment variable PORT
  // Other ports are firewalled. Default to 5000 if not specified.
  // this serves both the API and the client.
  // It is the only port that is not firewalled.
  const port = parseInt(process.env.PORT || '5000', 10);
  server.listen({
    port,
    host: "0.0.0.0",
    reusePort: true,
  }, () => {
    log(`serving on port ${port}`);
  });
})();

server/routes.ts.content:
import type { Express } from "express";
import { createServer, type Server } from "http";
import { storage } from "./storage";
import { googleMapsService } from "./services/googlemaps";
import { geminiService } from "./services/gemini";
import { mailgunService } from "./services/mailgun";
import { insertBookingSchema, insertHotelSchema, insertUserSchema, insertHotelImageSchema } from "@shared/schema";
import { z } from "zod";
import { authenticateUser, rateLimit } from "./middleware/auth";
import { createClient } from '@supabase/supabase-js';

// Create Supabase client for user data retrieval
const supabaseUrl = process.env.VITE_SUPABASE_URL!;
const supabaseAnonKey = process.env.VITE_SUPABASE_ANON_KEY!;
const supabase = createClient(supabaseUrl, supabaseAnonKey);

export async function registerRoutes(app: Express): Promise<Server> {

  // STEP 1: Create user in database immediately upon OAuth success
  app.post("/api/create-user", async (req, res) => {
    try {
      const { id, email, fullName, avatarUrl } = req.body;

      if (!id || !email) {
        return res.status(400).json({ message: "User ID and email are required" });
      }

      // Check if user already exists
      let user = await storage.getUser(id);

      if (!user) {
        // Create new user record
        user = await storage.createUser({
          id,
          email,
          fullName: fullName || null,
          avatarUrl: avatarUrl || null,
        });
        console.log(`✅ Created user in database: ${id}`);
      } else {
        console.log(`✅ User already exists in database: ${id}`);
      }

      res.json({ success: true, user });
    } catch (error) {
      console.error('Error creating user:', error);
      res.status(500).json({ 
        message: error instanceof Error ? error.message : "Failed to create user" 
      });
    }
  });

  // STEP 2: Fetch and store hotel data from Google Maps URL - SECURED with authentication
  app.post("/api/store-hotel-data", authenticateUser, rateLimit(300000, 10), async (req, res) => {
    try {
      const { mapsUrl } = req.body;
      const userId = req.user!.id; // Get userId from authenticated session

      if (!mapsUrl || typeof mapsUrl !== 'string') {
        return res.status(400).json({ 
          message: "Google Maps URL is required" 
        });
      }

      // Validate URL format
      const urlPatterns = [
        /^https:\/\/maps\.app\.goo\.gl\/\w+/,
        /^https:\/\/www\.google\.com\/maps/,
        /^https:\/\/maps\.google\.com/
      ];

      const isValidUrl = urlPatterns.some(pattern => pattern.test(mapsUrl));
      if (!isValidUrl) {
        return res.status(400).json({ 
          message: "Invalid Google Maps URL format" 
        });
      }

      // Check if user has an active hotel and deactivate it
      const hasActiveHotel = await storage.hasActiveHotel(userId);
      if (hasActiveHotel) {
        console.log(`User ${userId} has existing active hotel(s), deactivating them...`);
        const deactivatedCount = await storage.deactivateUserHotels(userId);
        console.log(`Deactivated ${deactivatedCount} hotels for user ${userId}`);
      }

      // Fetch hotel data from Google Maps
      const hotelData = await googleMapsService.fetchHotelFromUrl(mapsUrl);

      // Check if hotel already exists by place ID
      let hotel = await storage.getHotelByPlaceId(hotelData.placeId);

      if (hotel) {
        return res.status(409).json({ 
          message: "A hotel page already exists for this location",
          existingHotel: hotel
        });
      }

      // STEP 2: User should already exist (created during OAuth)
      console.log(`Fetching user from database: ${userId}`);
      let user = await storage.getUser(userId);

      if (!user) {
        return res.status(400).json({ 
          message: "User not found in database. Please sign in again." 
        });
      }

      console.log(`✅ User found in database:`, user);

      // STEP 2: Store hotel data in database FIRST (without AI content)
      const hotelCreateData = {
        ...hotelData,
        userId,
        googleMapsUrl: mapsUrl,
        // No AI content yet - will be added in next step
        headline: null,
        story: null,
        reviewSummary: null,
        // Convert null values to undefined for schema compatibility
        email: hotelData.email || undefined,
        website: hotelData.website || undefined,
        rating: hotelData.rating || undefined,
      };

      hotel = await storage.createHotel(hotelCreateData);
      console.log(`✅ Hotel data stored in database:`, hotel.id);

      // Create hotel images from the photos data
      const images = [];
      if (hotelData.photos && Array.isArray(hotelData.photos)) {
        for (let i = 0; i < hotelData.photos.length; i++) {
          const photo = hotelData.photos[i];
          const image = await storage.createHotelImage({
            hotelId: hotel.id,
            imageUrl: photo,
            isPrimary: i === 0, // First image is primary
            displayOrder: i,
          });
          images.push(image);
        }
      }

      res.json({
        hotel_id: hotel.id,
        hotel,
        images,
        message: hasActiveHotel 
          ? "Previous hotel page deactivated and hotel data stored successfully"
          : "Hotel data stored successfully. Ready for AI generation."
      });

    } catch (error) {
      console.error('Error generating hotel page:', error);
      res.status(500).json({ 
        message: error instanceof Error ? error.message : "Failed to generate hotel page" 
      });
    }
  });

  // STEP 3: Generate AI content from stored DB records
  app.post("/api/generate-ai-content", authenticateUser, async (req, res) => {
    try {
      const { hotel_id } = req.body;
      const userId = req.user!.id;

      if (!hotel_id) {
        return res.status(400).json({ message: "Hotel ID is required" });
      }

      // Get hotel data from database
      const hotel = await storage.getHotel(hotel_id);
      if (!hotel) {
        return res.status(404).json({ message: "Hotel not found" });
      }

      // Verify user owns this hotel
      if (hotel.userId !== userId) {
        return res.status(403).json({ message: "Access denied" });
      }

      // Generate AI content using DB records
      console.log(`✅ Generating AI content from DB records for hotel: ${hotel_id}`);
      const generatedContent = await geminiService.generateHotelContent({
        hotelName: hotel.name,
        address: hotel.address,
        category: hotel.category || 'Hotel',
        rating: hotel.rating || 0,
        reviews: hotel.reviews || [],
      });

      // Update hotel record with AI-generated content
      const updatedHotel = await storage.updateHotel(hotel_id, {
        headline: generatedContent.headline,
        story: generatedContent.story,
        reviewSummary: generatedContent.reviewSummary,
      });

      console.log(`✅ AI content generated and stored for hotel: ${hotel_id}`);

      res.json({
        hotel_id: hotel_id,
        content: generatedContent,
        hotel: updatedHotel,
        message: "AI content generated successfully from database records"
      });

    } catch (error) {
      console.error('Error generating AI content:', error);
      res.status(500).json({ 
        message: error instanceof Error ? error.message : "Failed to generate AI content" 
      });
    }
  });

  // STEP 4: Create shareable URL and return unique URL for copying
  app.post("/api/create-shareable-url", authenticateUser, async (req, res) => {
    try {
      const { hotel_id } = req.body;
      const userId = req.user!.id;

      if (!hotel_id) {
        return res.status(400).json({ message: "Hotel ID is required" });
      }

      // Get hotel data from database
      const hotel = await storage.getHotel(hotel_id);
      if (!hotel) {
        return res.status(404).json({ message: "Hotel not found" });
      }

      // Verify user owns this hotel
      if (hotel.userId !== userId) {
        return res.status(403).json({ message: "Access denied" });
      }

      // Ensure hotel has AI-generated content
      if (!hotel.headline || !hotel.story) {
        return res.status(400).json({ 
          message: "Hotel must have AI-generated content before creating shareable URL" 
        });
      }

      // Create unique shareable URL
      const shareableUrl = `${req.protocol}://${req.get('Host')}/hotel_id=${hotel_id}`;

      console.log(`✅ Shareable URL created for hotel: ${hotel_id} → ${shareableUrl}`);

      res.json({
        hotel_id: hotel_id,
        shareableUrl: shareableUrl,
        hotel: hotel,
        message: "Shareable URL created successfully. Copy and share this link!"
      });

    } catch (error) {
      console.error('Error creating shareable URL:', error);
      res.status(500).json({ 
        message: error instanceof Error ? error.message : "Failed to create shareable URL" 
      });
    }
  });

  // Create booking and send confirmation email
  app.post("/api/bookings", async (req, res) => {
    try {
      // Validate booking data
      const validationResult = insertBookingSchema.safeParse(req.body);

      if (!validationResult.success) {
        return res.status(400).json({ 
          message: "Invalid booking data",
          errors: validationResult.error.errors,
        });
      }

      const bookingData = validationResult.data;

      // Validate dates
      const checkinDate = new Date(bookingData.checkinDate);
      const checkoutDate = new Date(bookingData.checkoutDate);
      const today = new Date();
      today.setHours(0, 0, 0, 0);

      if (checkinDate < today) {
        return res.status(400).json({ 
          message: "Check-in date cannot be in the past" 
        });
      }

      if (checkoutDate <= checkinDate) {
        return res.status(400).json({ 
          message: "Check-out date must be after check-in date" 
        });
      }

      // Get hotel information
      const hotel = await storage.getHotel(bookingData.hotelId);
      if (!hotel) {
        return res.status(404).json({ 
          message: "Hotel not found" 
        });
      }

      // Create booking
      const booking = await storage.createBooking(bookingData);

      // Send confirmation email (only if Mailgun is configured)
      let emailStatus = 'skipped';
      let responseMessage = 'Booking confirmed successfully';

      if (mailgunService.isConfigured()) {
        try {
          await mailgunService.sendBookingConfirmation({
            email: booking.email,
            hotelName: hotel.name,
            checkinDate: booking.checkinDate,
            checkoutDate: booking.checkoutDate,
            roomType: booking.roomType,
            hotelAddress: hotel.address,
            hotelPhone: hotel.phone || undefined,
            bookingId: booking.id,
          });
          emailStatus = 'sent';
        } catch (emailError) {
          console.error('Email sending failed:', emailError);
          emailStatus = 'failed';
          responseMessage = 'Booking created successfully, but confirmation email could not be sent';
        }
      } else {
        console.warn('Mailgun not configured - skipping email');
        responseMessage = 'Booking confirmed successfully (email service not configured)';
      }

      res.status(201).json({
        booking,
        emailStatus,
        message: responseMessage,
      });

    } catch (error) {
      console.error('Error creating booking:', error);
      res.status(500).json({ 
        message: error instanceof Error ? error.message : "Failed to create booking" 
      });
    }
  });

  // Get hotel page data
  app.get("/api/hotels/:id", async (req, res) => {
    try {
      const { id } = req.params;

      const hotelPageData = await storage.getHotelPageData(id);

      if (!hotelPageData) {
        return res.status(404).json({ 
          message: "Hotel not found" 
        });
      }

      res.json(hotelPageData);

    } catch (error) {
      console.error('Error fetching hotel data:', error);
      res.status(500).json({ 
        message: "Failed to fetch hotel data" 
      });
    }
  });

  // User management routes - SECURED
  app.post("/api/users", authenticateUser, async (req, res) => {
    try {
      const authenticatedUserId = req.user!.id;
      const validationResult = insertUserSchema.safeParse({
        ...req.body,
        id: authenticatedUserId, // Use authenticated user ID
      });

      if (!validationResult.success) {
        return res.status(400).json({ 
          message: "Invalid user data",
          errors: validationResult.error.errors,
        });
      }

      const userData = validationResult.data;

      // Check if user already exists
      const existingUser = await storage.getUserByEmail(userData.email);
      if (existingUser) {
        return res.status(409).json({ 
          message: "User with this email already exists" 
        });
      }

      const user = await storage.createUser(userData);
      res.status(201).json(user);

    } catch (error) {
      console.error('Error creating user:', error);
      res.status(500).json({ 
        message: error instanceof Error ? error.message : "Failed to create user" 
      });
    }
  });

  // Get user with their hotel - SECURED
  app.get("/api/users/:id", authenticateUser, async (req, res) => {
    try {
      const { id } = req.params;
      const authenticatedUserId = req.user!.id;

      // Users can only access their own data
      if (id !== authenticatedUserId) {
        return res.status(403).json({ 
          message: "Access denied. You can only access your own user data." 
        });
      }

      const userWithHotel = await storage.getUserWithHotel(id);

      if (!userWithHotel) {
        return res.status(404).json({ 
          message: "User not found" 
        });
      }

      res.json(userWithHotel);

    } catch (error) {
      console.error('Error fetching user data:', error);
      res.status(500).json({ 
        message: "Failed to fetch user data" 
      });
    }
  });

  // Get user's saved hotels - SECURED
  app.get("/api/user/hotels", authenticateUser, async (req, res) => {
    try {
      const authenticatedUserId = req.user!.id;
      const hotels = await storage.getHotelsByUserId(authenticatedUserId);

      res.json({ 
        hotels: hotels,
        message: `Found ${hotels.length} saved hotels` 
      });

    } catch (error) {
      console.error('Error fetching user hotels:', error);
      res.status(500).json({ 
        message: "Failed to fetch your saved hotels" 
      });
    }
  });

  // Hotel Images management routes - SECURED
  app.post("/api/hotels/:id/images", authenticateUser, async (req, res) => {
    try {
      const { id } = req.params;
      const authenticatedUserId = req.user!.id;
      const validationResult = insertHotelImageSchema.safeParse({
        ...req.body,
        hotelId: id,
      });

      if (!validationResult.success) {
        return res.status(400).json({ 
          message: "Invalid image data",
          errors: validationResult.error.errors,
        });
      }

      const imageData = validationResult.data;

      // Verify hotel exists and user owns it
      const hotel = await storage.getHotel(id);
      if (!hotel) {
        return res.status(404).json({ 
          message: "Hotel not found" 
        });
      }

      if (hotel.userId !== authenticatedUserId) {
        return res.status(403).json({ 
          message: "Access denied. You can only manage your own hotel's images." 
        });
      }

      const image = await storage.createHotelImage(imageData);
      res.status(201).json(image);

    } catch (error) {
      console.error('Error creating hotel image:', error);
      res.status(500).json({ 
        message: error instanceof Error ? error.message : "Failed to create hotel image" 
      });
    }
  });

  app.get("/api/hotels/:id/images", async (req, res) => {
    try {
      const { id } = req.params;

      // Verify hotel exists
      const hotel = await storage.getHotel(id);
      if (!hotel) {
        return res.status(404).json({ 
          message: "Hotel not found" 
        });
      }

      const images = await storage.getHotelImages(id);
      res.json(images);

    } catch (error) {
      console.error('Error fetching hotel images:', error);
      res.status(500).json({ 
        message: "Failed to fetch hotel images" 
      });
    }
  });

  app.put("/api/hotels/:hotelId/images/:imageId/primary", authenticateUser, async (req, res) => {
    try {
      const { hotelId, imageId } = req.params;
      const authenticatedUserId = req.user!.id;

      // Verify hotel exists and user owns it
      const hotel = await storage.getHotel(hotelId);
      if (!hotel) {
        return res.status(404).json({ 
          message: "Hotel not found" 
        });
      }

      if (hotel.userId !== authenticatedUserId) {
        return res.status(403).json({ 
          message: "Access denied. You can only manage your own hotel's images." 
        });
      }

      const success = await storage.setPrimaryImage(hotelId, imageId);

      if (!success) {
        return res.status(404).json({ 
          message: "Image not found" 
        });
      }

      res.json({ message: "Primary image updated successfully" });

    } catch (error) {
      console.error('Error setting primary image:', error);
      res.status(500).json({ 
        message: "Failed to set primary image" 
      });
    }
  });

  // Get hotel bookings (for hotel management) - SECURED
  app.get("/api/hotels/:id/bookings", authenticateUser, async (req, res) => {
    try {
      const { id } = req.params;
      const authenticatedUserId = req.user!.id;

      // Verify hotel exists and user owns it
      const hotel = await storage.getHotel(id);
      if (!hotel) {
        return res.status(404).json({ 
          message: "Hotel not found" 
        });
      }

      if (hotel.userId !== authenticatedUserId) {
        return res.status(403).json({ 
          message: "Access denied. You can only view bookings for your own hotel." 
        });
      }

      const bookings = await storage.getHotelBookings(id);
      res.json(bookings);

    } catch (error) {
      console.error('Error fetching hotel bookings:', error);
      res.status(500).json({ 
        message: "Failed to fetch hotel bookings" 
      });
    }
  });

  const httpServer = createServer(app);
  return httpServer;
}

server/storage.ts.content:
import { 
  type User, 
  type InsertUser,
  type Hotel, 
  type InsertHotel,
  type HotelImage,
  type InsertHotelImage,
  type Booking, 
  type InsertBooking, 
  type HotelPageData,
  type HotelWithImages,
  type UserWithHotel,
  users,
  hotels,
  hotelImages,
  bookings
} from "@shared/schema";
import { randomUUID } from "crypto";
import { db } from "./db";
import { eq, and, desc } from "drizzle-orm";

export interface IStorage {
  // User operations
  getUser(id: string): Promise<User | undefined>;
  getUserByEmail(email: string): Promise<User | undefined>;
  createUser(user: InsertUser): Promise<User>;
  updateUser(id: string, updates: Partial<InsertUser>): Promise<User | undefined>;

  // Hotel operations  
  getHotel(id: string): Promise<Hotel | undefined>;
  getHotelByPlaceId(placeId: string): Promise<Hotel | undefined>;
  getHotelByUserId(userId: string): Promise<Hotel | undefined>;
  getHotelsByUserId(userId: string): Promise<Hotel[]>;
  getActiveHotelByUserId(userId: string): Promise<Hotel | undefined>;
  createHotel(hotel: InsertHotel): Promise<Hotel>;
  updateHotel(id: string, updates: Partial<InsertHotel>): Promise<Hotel | undefined>;
  deleteHotel(id: string): Promise<boolean>;
  deactivateUserHotels(userId: string): Promise<number>;

  // Hotel Images operations
  getHotelImages(hotelId: string): Promise<HotelImage[]>;
  createHotelImage(image: InsertHotelImage): Promise<HotelImage>;
  updateHotelImage(id: string, updates: Partial<InsertHotelImage>): Promise<HotelImage | undefined>;
  deleteHotelImage(id: string): Promise<boolean>;
  setPrimaryImage(hotelId: string, imageId: string): Promise<boolean>;

  // Booking operations
  createBooking(booking: InsertBooking): Promise<Booking>;
  getBooking(id: string): Promise<Booking | undefined>;
  getHotelBookings(hotelId: string): Promise<Booking[]>;

  // Combined operations
  getHotelPageData(hotelId: string): Promise<HotelPageData | undefined>;
  getHotelWithImages(hotelId: string): Promise<HotelWithImages | undefined>;
  getUserWithHotel(userId: string): Promise<UserWithHotel | undefined>;

  // Validation and utilities
  canUserCreateHotel(userId: string): Promise<boolean>;
  hasActiveHotel(userId: string): Promise<boolean>;
}

export class MemStorage implements IStorage {
  private users: Map<string, User>;
  private hotels: Map<string, Hotel>;
  private hotelImages: Map<string, HotelImage>;
  private bookings: Map<string, Booking>;

  constructor() {
    this.users = new Map();
    this.hotels = new Map();
    this.hotelImages = new Map();
    this.bookings = new Map();
  }

  // User operations
  async getUser(id: string): Promise<User | undefined> {
    return this.users.get(id);
  }

  async getUserByEmail(email: string): Promise<User | undefined> {
    return Array.from(this.users.values()).find(user => user.email === email);
  }

  async createUser(insertUser: InsertUser): Promise<User> {
    const user: User = {
      ...insertUser,
      fullName: insertUser.fullName ?? null,
      avatarUrl: insertUser.avatarUrl ?? null,
      createdAt: new Date(),
      updatedAt: new Date(),
    };
    this.users.set(user.id, user);
    return user;
  }

  async updateUser(id: string, updates: Partial<InsertUser>): Promise<User | undefined> {
    const existingUser = this.users.get(id);
    if (!existingUser) return undefined;

    const updatedUser: User = {
      ...existingUser,
      ...updates,
      updatedAt: new Date(),
    };
    this.users.set(id, updatedUser);
    return updatedUser;
  }

  // Hotel operations
  async getHotel(id: string): Promise<Hotel | undefined> {
    return this.hotels.get(id);
  }

  async getHotelByPlaceId(placeId: string): Promise<Hotel | undefined> {
    return Array.from(this.hotels.values()).find(hotel => hotel.placeId === placeId);
  }

  async getHotelByUserId(userId: string): Promise<Hotel | undefined> {
    return Array.from(this.hotels.values()).find(hotel => hotel.userId === userId);
  }

  async getHotelsByUserId(userId: string): Promise<Hotel[]> {
    return Array.from(this.hotels.values()).filter(hotel => hotel.userId === userId);
  }

  async getActiveHotelByUserId(userId: string): Promise<Hotel | undefined> {
    return Array.from(this.hotels.values()).find(hotel => hotel.userId === userId && hotel.isActive);
  }

  async createHotel(insertHotel: InsertHotel): Promise<Hotel> {
    const id = randomUUID();
    const hotel: Hotel = {
      ...insertHotel,
      id,
      description: insertHotel.description ?? null,
      city: insertHotel.city ?? null,
      phone: insertHotel.phone ?? null,
      email: insertHotel.email ?? null,
      website: insertHotel.website ?? null,
      rating: insertHotel.rating ?? null,
      category: insertHotel.category ?? null,
      yearsInService: insertHotel.yearsInService ?? null,
      headline: insertHotel.headline ?? null,
      story: insertHotel.story ?? null,
      reviewSummary: insertHotel.reviewSummary ?? null,
      features: Array.isArray(insertHotel.features) ? insertHotel.features as string[] : [],
      priceRange: insertHotel.priceRange ?? null,
      currency: insertHotel.currency ?? "USD",
      coordinates: insertHotel.coordinates ?? null,
      reviews: Array.isArray(insertHotel.reviews) ? insertHotel.reviews as Array<{author: string; text: string; rating: number; date: string}> : [],
      isActive: insertHotel.isActive ?? true,
      createdAt: new Date(),
      updatedAt: new Date(),
    };
    this.hotels.set(id, hotel);
    return hotel;
  }

  async deactivateUserHotels(userId: string): Promise<number> {
    const userHotels = Array.from(this.hotels.values()).filter(hotel => hotel.userId === userId && hotel.isActive);
    let deactivatedCount = 0;

    for (const hotel of userHotels) {
      const updated = await this.updateHotel(hotel.id, { isActive: false });
      if (updated) {
        deactivatedCount++;
      }
    }

    return deactivatedCount;
  }

  async updateHotel(id: string, updates: Partial<InsertHotel>): Promise<Hotel | undefined> {
    const existingHotel = this.hotels.get(id);
    if (!existingHotel) return undefined;

    const updatedHotel: Hotel = {
      ...existingHotel,
      ...updates,
      // Ensure proper array types for features and reviews
      features: updates.features ? (Array.isArray(updates.features) ? updates.features as string[] : []) : existingHotel.features,
      reviews: updates.reviews ? (Array.isArray(updates.reviews) ? updates.reviews as Array<{author: string; text: string; rating: number; date: string}> : []) : existingHotel.reviews,
      updatedAt: new Date(),
    };
    this.hotels.set(id, updatedHotel);
    return updatedHotel;
  }

  async deleteHotel(id: string): Promise<boolean> {
    return this.hotels.delete(id);
  }

  // Hotel Images operations
  async getHotelImages(hotelId: string): Promise<HotelImage[]> {
    return Array.from(this.hotelImages.values())
      .filter(image => image.hotelId === hotelId)
      .sort((a, b) => (a.displayOrder ?? 0) - (b.displayOrder ?? 0));
  }

  async createHotelImage(insertImage: InsertHotelImage): Promise<HotelImage> {
    const id = randomUUID();
    const image: HotelImage = {
      ...insertImage,
      id,
      altText: insertImage.altText ?? null,
      caption: insertImage.caption ?? null,
      isPrimary: insertImage.isPrimary ?? false,
      displayOrder: insertImage.displayOrder ?? 0,
      createdAt: new Date(),
    };
    this.hotelImages.set(id, image);
    return image;
  }

  async updateHotelImage(id: string, updates: Partial<InsertHotelImage>): Promise<HotelImage | undefined> {
    const existingImage = this.hotelImages.get(id);
    if (!existingImage) return undefined;

    const updatedImage: HotelImage = {
      ...existingImage,
      ...updates,
    };
    this.hotelImages.set(id, updatedImage);
    return updatedImage;
  }

  async deleteHotelImage(id: string): Promise<boolean> {
    return this.hotelImages.delete(id);
  }

  async setPrimaryImage(hotelId: string, imageId: string): Promise<boolean> {
    // First, unset all primary flags for this hotel
    const hotelImages = await this.getHotelImages(hotelId);
    for (const image of hotelImages) {
      if (image.isPrimary) {
        await this.updateHotelImage(image.id, { isPrimary: false });
      }
    }

    // Set the specified image as primary
    const targetImage = this.hotelImages.get(imageId);
    if (!targetImage || targetImage.hotelId !== hotelId) return false;

    await this.updateHotelImage(imageId, { isPrimary: true });
    return true;
  }

  // Booking operations
  async createBooking(insertBooking: InsertBooking): Promise<Booking> {
    const id = randomUUID();
    const booking: Booking = {
      ...insertBooking,
      id,
      guestCount: insertBooking.guestCount ?? 1,
      specialRequests: insertBooking.specialRequests ?? null,
      status: insertBooking.status ?? "confirmed",
      createdAt: new Date(),
    };
    this.bookings.set(id, booking);
    return booking;
  }

  async getBooking(id: string): Promise<Booking | undefined> {
    return this.bookings.get(id);
  }

  async getHotelBookings(hotelId: string): Promise<Booking[]> {
    return Array.from(this.bookings.values())
      .filter(booking => booking.hotelId === hotelId)
      .sort((a, b) => (b.createdAt?.getTime() ?? 0) - (a.createdAt?.getTime() ?? 0));
  }

  // Combined operations
  async getHotelPageData(hotelId: string): Promise<HotelPageData | undefined> {
    const hotel = await this.getHotel(hotelId);
    if (!hotel) return undefined;

    const user = await this.getUser(hotel.userId);
    if (!user) return undefined;

    const images = await this.getHotelImages(hotelId);

    return { hotel, images, user };
  }

  async getHotelWithImages(hotelId: string): Promise<HotelWithImages | undefined> {
    const hotel = await this.getHotel(hotelId);
    if (!hotel) return undefined;

    const images = await this.getHotelImages(hotelId);
    return { hotel, images };
  }

  async getUserWithHotel(userId: string): Promise<UserWithHotel | undefined> {
    const user = await this.getUser(userId);
    if (!user) return undefined;

    const hotel = await this.getActiveHotelByUserId(userId);
    return { user, hotel: hotel || null };
  }

  // Validation and utilities
  async canUserCreateHotel(userId: string): Promise<boolean> {
    // Users can always create hotels, but existing active hotels will be deactivated
    return true;
  }

  async hasActiveHotel(userId: string): Promise<boolean> {
    const activeHotel = await this.getActiveHotelByUserId(userId);
    return !!activeHotel;
  }
}

// DatabaseStorage implementation using PostgreSQL via Drizzle ORM
export class DatabaseStorage implements IStorage {
  // User operations
  async getUser(id: string): Promise<User | undefined> {
    const [user] = await db.select().from(users).where(eq(users.id, id));
    return user || undefined;
  }

  async getUserByEmail(email: string): Promise<User | undefined> {
    const [user] = await db.select().from(users).where(eq(users.email, email));
    return user || undefined;
  }

  async createUser(insertUser: InsertUser): Promise<User> {
    const [user] = await db.insert(users).values(insertUser).returning();
    return user;
  }

  async updateUser(id: string, updates: Partial<InsertUser>): Promise<User | undefined> {
    const [user] = await db
      .update(users)
      .set({ ...updates, updatedAt: new Date() })
      .where(eq(users.id, id))
      .returning();
    return user || undefined;
  }

  // Hotel operations
  async getHotel(id: string): Promise<Hotel | undefined> {
    const [hotel] = await db.select().from(hotels).where(eq(hotels.id, id));
    return hotel || undefined;
  }

  async getHotelByPlaceId(placeId: string): Promise<Hotel | undefined> {
    const [hotel] = await db.select().from(hotels).where(eq(hotels.placeId, placeId));
    return hotel || undefined;
  }

  async getHotelByUserId(userId: string): Promise<Hotel | undefined> {
    const [hotel] = await db.select().from(hotels).where(eq(hotels.userId, userId));
    return hotel || undefined;
  }

  async getActiveHotelByUserId(userId: string): Promise<Hotel | undefined> {
    const [hotel] = await db
      .select()
      .from(hotels)
      .where(and(eq(hotels.userId, userId), eq(hotels.isActive, true)));
    return hotel || undefined;
  }

  async createHotel(insertHotel: InsertHotel): Promise<Hotel> {
    const [hotel] = await db.insert(hotels).values(insertHotel as any).returning();
    return hotel;
  }

  async updateHotel(id: string, updates: Partial<InsertHotel>): Promise<Hotel | undefined> {
    const [hotel] = await db
      .update(hotels)
      .set({ ...updates, updatedAt: new Date() } as any)
      .where(eq(hotels.id, id))
      .returning();
    return hotel || undefined;
  }

  async deleteHotel(id: string): Promise<boolean> {
    const result = await db.delete(hotels).where(eq(hotels.id, id));
    return (result.rowCount ?? 0) > 0;
  }

  async deactivateUserHotels(userId: string): Promise<number> {
    const result = await db
      .update(hotels)
      .set({ isActive: false, updatedAt: new Date() })
      .where(and(eq(hotels.userId, userId), eq(hotels.isActive, true)));
    return result.rowCount || 0;
  }

  // Hotel Images operations
  async getHotelImages(hotelId: string): Promise<HotelImage[]> {
    return await db
      .select()
      .from(hotelImages)
      .where(eq(hotelImages.hotelId, hotelId))
      .orderBy(hotelImages.displayOrder);
  }

  async createHotelImage(insertImage: InsertHotelImage): Promise<HotelImage> {
    const [image] = await db.insert(hotelImages).values(insertImage).returning();
    return image;
  }

  async updateHotelImage(id: string, updates: Partial<InsertHotelImage>): Promise<HotelImage | undefined> {
    const [image] = await db
      .update(hotelImages)
      .set(updates)
      .where(eq(hotelImages.id, id))
      .returning();
    return image || undefined;
  }

  async deleteHotelImage(id: string): Promise<boolean> {
    const result = await db.delete(hotelImages).where(eq(hotelImages.id, id));
    return (result.rowCount ?? 0) > 0;
  }

  async setPrimaryImage(hotelId: string, imageId: string): Promise<boolean> {
    // First, unset all primary flags for this hotel
    await db
      .update(hotelImages)
      .set({ isPrimary: false })
      .where(eq(hotelImages.hotelId, hotelId));

    // Set the specified image as primary
    const result = await db
      .update(hotelImages)
      .set({ isPrimary: true })
      .where(and(eq(hotelImages.id, imageId), eq(hotelImages.hotelId, hotelId)));

    return (result.rowCount ?? 0) > 0;
  }

  // Booking operations
  async createBooking(insertBooking: InsertBooking): Promise<Booking> {
    const [booking] = await db.insert(bookings).values(insertBooking).returning();
    return booking;
  }

  async getBooking(id: string): Promise<Booking | undefined> {
    const [booking] = await db.select().from(bookings).where(eq(bookings.id, id));
    return booking || undefined;
  }

  async getHotelBookings(hotelId: string): Promise<Booking[]> {
    return await db
      .select()
      .from(bookings)
      .where(eq(bookings.hotelId, hotelId))
      .orderBy(desc(bookings.createdAt));
  }

  // Combined operations
  async getHotelPageData(hotelId: string): Promise<HotelPageData | undefined> {
    const hotel = await this.getHotel(hotelId);
    if (!hotel) return undefined;

    const user = await this.getUser(hotel.userId);
    if (!user) return undefined;

    const images = await this.getHotelImages(hotelId);

    return { hotel, images, user };
  }

  async getHotelWithImages(hotelId: string): Promise<HotelWithImages | undefined> {
    const hotel = await this.getHotel(hotelId);
    if (!hotel) return undefined;

    const images = await this.getHotelImages(hotelId);
    return { hotel, images };
  }

  async getUserWithHotel(userId: string): Promise<UserWithHotel | undefined> {
    const user = await this.getUser(userId);
    if (!user) return undefined;

    const hotel = await this.getActiveHotelByUserId(userId);
    return { user, hotel: hotel || null };
  }

  // Validation and utilities
  async canUserCreateHotel(userId: string): Promise<boolean> {
    // Users can always create hotels, but existing active hotels will be deactivated
    return true;
  }

  async hasActiveHotel(userId: string): Promise<boolean> {
    const activeHotel = await this.getActiveHotelByUserId(userId);
    return !!activeHotel;
  }
}

// Use DatabaseStorage instead of MemStorage - commented for blueprint integration reference
export const storage = new DatabaseStorage();

