import { GoogleGenAI } from "@google/genai";

interface HotelContentRequest {
  hotelName: string;
  address: string;
  category: string;
  rating: number;
  reviews: Array<{
    author: string;
    text: string;
    rating: number;
    date: string;
  }>;
}

interface GeneratedHotelContent {
  headline: string;
  story: string;
  reviewSummary: string;
}

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    const apiKey = process.env.GEMINI_API_KEY || '';
    if (!apiKey) {
      throw new Error('Gemini API key is required');
    }
    this.ai = new GoogleGenAI({ apiKey });
  }

  private async sleep(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  async generateHotelContent(hotelData: HotelContentRequest): Promise<GeneratedHotelContent> {
    const maxRetries = 3;
    const baseDelay = 1000; // 1 second

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        const systemPrompt = `You are an expert hotel marketing copywriter. Generate compelling marketing content for hotels that will attract guests and showcase the unique value proposition.

Your task is to create:
1. A catchy headline (max 60 characters) that captures the hotel's essence
2. A compelling "Our Story" section (2-3 paragraphs) that tells the hotel's narrative
3. A review summary (1 paragraph) that synthesizes guest feedback

Guidelines:
- Use an engaging, luxurious tone
- Highlight unique selling points
- Make content feel authentic and personal
- Focus on experiences and emotions
- Avoid generic hotel descriptions`;

        const prompt = `Generate marketing content for this hotel:

Hotel Name: ${hotelData.hotelName}
Location: ${hotelData.address}
Category: ${hotelData.category}
Rating: ${hotelData.rating}/5 stars

Guest Reviews:
${hotelData.reviews.map(review => 
  `- ${review.author} (${review.rating}/5): "${review.text}"`
).join('\n')}

Please respond with JSON in this exact format:
{
  "headline": "Your catchy headline here",
  "story": "Your multi-paragraph story here with proper line breaks",
  "reviewSummary": "Your review summary here"
}`;

        console.log(`Attempting to generate hotel content (attempt ${attempt}/${maxRetries})`);

        const response = await this.ai.models.generateContent({
          model: "gemini-2.5-pro",
          config: {
            systemInstruction: systemPrompt,
            responseMimeType: "application/json",
            responseSchema: {
              type: "object",
              properties: {
                headline: { type: "string" },
                story: { type: "string" },
                reviewSummary: { type: "string" },
              },
              required: ["headline", "story", "reviewSummary"],
            },
          },
          contents: prompt,
        });

        const rawJson = response.text;
        if (!rawJson) {
          throw new Error("Empty response from Gemini AI");
        }

        const generatedContent: GeneratedHotelContent = JSON.parse(rawJson);

        // Validate the generated content
        if (!generatedContent.headline || !generatedContent.story || !generatedContent.reviewSummary) {
          throw new Error("Incomplete content generated by AI");
        }

        console.log(`Successfully generated hotel content on attempt ${attempt}`);
        return generatedContent;

      } catch (error: any) {
        console.error(`Error generating hotel content with Gemini (attempt ${attempt}/${maxRetries}):`, error);

        // Check if this is a retryable error (503 service unavailable)
        const isRetryableError = error?.status === 503 || 
                                error?.message?.includes('overloaded') ||
                                error?.message?.includes('503') ||
                                error?.message?.includes('UNAVAILABLE');

        if (isRetryableError && attempt < maxRetries) {
          const delay = baseDelay * Math.pow(2, attempt - 1); // Exponential backoff
          console.log(`Model is overloaded, retrying in ${delay}ms... (attempt ${attempt + 1}/${maxRetries})`);
          await this.sleep(delay);
          continue;
        }

        // If we've exhausted retries or it's not a retryable error
        if (attempt === maxRetries) {
          throw new Error(`Failed to generate hotel content after ${maxRetries} attempts: ${error instanceof Error ? error.message : 'Unknown error'}`);
        } else {
          throw new Error(`Failed to generate hotel content: ${error instanceof Error ? error.message : 'Unknown error'}`);
        }
      }
    }

    // This should never be reached due to the loop logic, but TypeScript requires it
    throw new Error('Unexpected error: Failed to generate hotel content');
  }
}

export const geminiService = new GeminiService();

server/services/googlemaps.ts.content:
interface GoogleMapsPlace {
  place_id: string;
  name: string;
  formatted_address: string;
  formatted_phone_number?: string;
  website?: string;
  rating?: number;
  photos?: Array<{
    photo_reference: string;
    width: number;
    height: number;
  }>;
  reviews?: Array<{
    author_name: string;
    text: string;
    rating: number;
    relative_time_description: string;
  }>;
  geometry: {
    location: {
      lat: number;
      lng: number;
    };
  };
  types: string[];
}

interface GoogleMapsResponse {
  result: GoogleMapsPlace;
  status: string;
}

export class GoogleMapsService {
  private apiKey: string;
  private baseUrl = 'https://places.googleapis.com/v1';

  constructor() {
    this.apiKey = process.env.GOOGLE_MAPS_API_KEY || process.env.GOOGLE_PLACES_API_KEY || '';
    if (!this.apiKey) {
      throw new Error('Google Maps API key is required');
    }
  }

  async extractPlaceIdFromUrl(url: string): Promise<string | null> {
    try {
      const urlObj = new URL(url);
      const params = new URLSearchParams(urlObj.search);

      // Check for direct place_id parameters
      const placeIdParams = [
        'place_id',
        'query_place_id',
        'origin_place_id', 
        'destination_place_id'
      ];

      for (const param of placeIdParams) {
        const placeId = params.get(param);
        if (placeId && placeId.startsWith('ChIJ')) {
          return placeId;
        }
      }

      // Check for q=place_id: format
      const qParam = params.get('q');
      if (qParam && qParam.startsWith('place_id:')) {
        const placeId = qParam.replace('place_id:', '');
        if (placeId.startsWith('ChIJ')) {
          return placeId;
        }
      }

      // Handle URLs with embedded place data - look for ftid parameter
      const ftid = params.get('ftid');
      if (ftid && ftid.startsWith('0x')) {
        // Try to extract place_id from the URL path or other parameters
        const pathMatch = url.match(/\/maps\/place\/[^@]+@[^\/]+\/data=([^!]+)/);
        if (pathMatch) {
          // Look for place_id in the data parameter
          const dataMatch = pathMatch[1].match(/!1s([A-Za-z0-9_-]+)/);
          if (dataMatch && dataMatch[1].startsWith('ChIJ')) {
            return dataMatch[1];
          }
        }
      }

      // Fallback: extract place name from URL and use Text Search
      const placeName = this.extractPlaceNameFromUrl(url);
      if (placeName) {
        console.log('No direct place_id found, attempting text search for:', placeName);
        return await this.getPlaceIdFromTextSearch(placeName);
      }

      console.log('Could not extract valid place_id or place name from URL:', url);
      return null;
    } catch (error) {
      console.error('Error parsing URL:', error);
      return null;
    }
  }

  extractPlaceNameFromUrl(url: string): string | null {
    try {
      // Extract place name from various Google Maps URL formats
      const patterns = [
        /\/maps\/place\/([^@/?]+)/,  // Standard place URLs
        /\/maps\/search\/([^@/?]+)/, // Search URLs
        /[?&]q=([^&]+)/              // Query parameter
      ];

      for (const pattern of patterns) {
        const match = url.match(pattern);
        if (match) {
          const placeName = decodeURIComponent(match[1].replace(/\+/g, ' '));
          // Clean up the place name
          return placeName.replace(/[^\w\s,-]/g, ' ').trim();
        }
      }

      return null;
    } catch (error) {
      console.error('Error extracting place name:', error);
      return null;
    }
  }

  async getPlaceIdFromTextSearch(placeName: string): Promise<string | null> {
    try {
      const url = `${this.baseUrl}/places:searchText`;

      const response = await fetch(url, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-Goog-Api-Key': this.apiKey,
          'X-Goog-FieldMask': 'places.id,places.displayName'
        },
        body: JSON.stringify({
          textQuery: placeName,
          maxResultCount: 1
        })
      });

      if (!response.ok) {
        console.error('Text search failed:', response.status, response.statusText);
        return null;
      }

      const data = await response.json();
      if (data.places && data.places.length > 0) {
        const placeId = data.places[0].id;
        console.log('Found place_id via text search:', placeId);
        return placeId;
      }

      return null;
    } catch (error) {
      console.error('Error in text search:', error);
      return null;
    }
  }

  async resolveShortUrl(shortUrl: string): Promise<string> {
    try {
      const response = await fetch(shortUrl, { 
        method: 'HEAD',
        redirect: 'follow'
      });
      return response.url;
    } catch (error) {
      console.error('Error resolving short URL:', error);
      return shortUrl;
    }
  }

  async getPlaceDetails(placeId: string): Promise<GoogleMapsPlace> {
    // Field mask for new Places API - specify which fields we want
    const fieldMask = [
      'id',
      'displayName',
      'formattedAddress', 
      'nationalPhoneNumber',
      'websiteUri',
      'rating',
      'photos',
      'reviews',
      'location',
      'types'
    ].join(',');

    const url = `${this.baseUrl}/places/${placeId}`;
    console.log('Making Google Maps API (New) request to:', url);

    const response = await fetch(url, {
      method: 'GET',
      headers: {
        'Content-Type': 'application/json',
        'X-Goog-Api-Key': this.apiKey,
        'X-Goog-FieldMask': fieldMask
      }
    });

    if (!response.ok) {
      console.error('Google Maps API HTTP error:', response.status, response.statusText);
      const errorText = await response.text();
      console.error('Error response body:', errorText);

      try {
        const errorData = JSON.parse(errorText);
        if (errorData.error?.status === 'INVALID_ARGUMENT' && errorData.error?.message?.includes('Place ID')) {
          throw new Error('Invalid place ID. Please check that you\'re using a valid Google Maps URL for a hotel.');
        }
      } catch (parseError) {
        // If we can't parse the error, fall back to generic message
      }

      throw new Error(`Google Maps API HTTP error: ${response.status} ${response.statusText}`);
    }

    const data = await response.json();
    console.log('Google Maps API response received successfully');

    // Transform new API response to match legacy format for compatibility
    const transformedData: GoogleMapsPlace = {
      place_id: data.id || placeId,
      name: data.displayName?.text || '',
      formatted_address: data.formattedAddress || '',
      formatted_phone_number: data.nationalPhoneNumber || undefined,
      website: data.websiteUri || undefined,
      rating: data.rating || undefined,
      photos: data.photos?.map((photo: any) => ({
        photo_reference: photo.name, // New API uses 'name' field
        width: photo.widthPx || 800,
        height: photo.heightPx || 600
      })) || [],
      reviews: data.reviews?.map((review: any) => ({
        author_name: review.authorAttribution?.displayName || 'Anonymous',
        text: review.text?.text || '',
        rating: review.rating || 0,
        relative_time_description: review.relativePublishTimeDescription || ''
      })) || [],
      geometry: {
        location: {
          lat: data.location?.latitude || 0,
          lng: data.location?.longitude || 0
        }
      },
      types: data.types || []
    };

    return transformedData;
  }

  async getPhotoUrl(photoName: string, maxWidth: number = 800): Promise<string> {
    // New Places API uses a different photo endpoint format
    return `https://places.googleapis.com/v1/${photoName}/media?maxWidthPx=${maxWidth}&key=${this.apiKey}`;
  }

  async fetchHotelFromUrl(mapsUrl: string) {
    try {
      // If it's a short URL, resolve it first
      let resolvedUrl = mapsUrl;
      if (mapsUrl.includes('maps.app.goo.gl')) {
        resolvedUrl = await this.resolveShortUrl(mapsUrl);
      }

      // Extract place ID
      const placeId = await this.extractPlaceIdFromUrl(resolvedUrl);
      if (!placeId) {
        throw new Error('Could not extract place ID from URL');
      }

      // Fetch place details
      const place = await this.getPlaceDetails(placeId);

      // Process photos
      const photos: string[] = [];
      if (place.photos) {
        for (const photo of place.photos.slice(0, 8)) {
          const photoUrl = await this.getPhotoUrl(photo.photo_reference);
          photos.push(photoUrl);
        }
      }

      // Process reviews
      const reviews = place.reviews?.slice(0, 6).map(review => ({
        author: review.author_name,
        text: review.text,
        rating: review.rating,
        date: review.relative_time_description,
      })) || [];

      // Extract city from address
      const addressParts = place.formatted_address.split(', ');
      const city = addressParts.length > 2 ? addressParts[addressParts.length - 3] : '';

      // Determine category based on types and rating
      let category = 'Hotel';
      if (place.types.includes('luxury_hotel') || (place.rating && place.rating >= 4.5)) {
        category = '5-Star Luxury';
      } else if (place.rating && place.rating >= 4.0) {
        category = '4-Star Premium';
      } else if (place.rating && place.rating >= 3.5) {
        category = '3-Star Standard';
      }

      return {
        placeId: place.place_id,
        name: place.name,
        address: place.formatted_address,
        city,
        phone: place.formatted_phone_number || null,
        email: null, // Not available from Google Maps
        website: place.website || null,
        rating: place.rating || null,
        category,
        yearsInService: null, // Not available from Google Maps
        photos,
        reviews,
        coordinates: {
          lat: place.geometry.location.lat,
          lng: place.geometry.location.lng,
        },
      };
    } catch (error) {
      console.error('Error fetching hotel from Google Maps:', error);
      throw new Error(`Failed to fetch hotel data: ${error instanceof Error ? error.message : 'Unknown error'}`);
    }
  }
}

export const googleMapsService = new GoogleMapsService();

server/services/mailgun.ts.content:
interface BookingConfirmationData {
  email: string;
  hotelName: string;
  checkinDate: string;
  checkoutDate: string;
  roomType: string;
  hotelAddress: string;
  hotelPhone?: string;
  bookingId: string;
}

export class MailgunService {
  private apiKey: string;
  private domain: string;
  private senderEmail: string;
  private baseUrl: string;

  constructor() {
    this.apiKey = process.env.MAILGUN_API_KEY || '';
    this.domain = process.env.MAILGUN_DOMAIN || '';
    this.senderEmail = process.env.MAILGUN_SENDER_EMAIL || 'Mailgun Sandbox <postmaster@www.kutkrew.com>';
    this.baseUrl = `https://api.mailgun.net/v3/${this.domain}`;
  }

  isConfigured(): boolean {
    return !!(this.apiKey && this.domain);
  }

  async sendBookingConfirmation(bookingData: BookingConfirmationData): Promise<void> {
    try {
      // Debug logging
      console.log('Mailgun Debug Info:');
      console.log('- API Key present:', !!this.apiKey);
      console.log('- API Key length:', this.apiKey?.length || 0);
      console.log('- Domain:', this.domain);
      console.log('- Sender Email:', this.senderEmail);
      console.log('- Base URL:', this.baseUrl);

      const emailContent = this.generateBookingEmail(bookingData);

      const formData = new FormData();
      formData.append('from', this.senderEmail);
      formData.append('to', bookingData.email);
      formData.append('subject', `Booking Confirmation - ${bookingData.hotelName}`);
      formData.append('html', emailContent);

      const response = await fetch(`${this.baseUrl}/messages`, {
        method: 'POST',
        headers: {
          'Authorization': `Basic ${Buffer.from(`api:${this.apiKey}`).toString('base64')}`,
        },
        body: formData,
      });

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(`Mailgun API error: ${response.status} - ${errorText}`);
      }

      const result = await response.json();
      console.log('Email sent successfully:', result.id);
    } catch (error) {
      console.error('Error sending booking confirmation email:', error);
      throw new Error(`Failed to send confirmation email: ${error instanceof Error ? error.message : 'Unknown error'}`);
    }
  }

