                {content.headline}
              </p>
              <div className="flex items-center justify-center space-x-6 text-lg flex-wrap gap-4">
                <div className="flex items-center">
                  <div className="flex text-yellow-400 mr-2">
                    {renderStars(hotel.rating || 0)}
